INSERT INTO courses (id, path_id, title, slug, description, order_index) VALUES ('f363c705-70f7-4065-a2b2-1d3df859714c', 'f4f7844a-e0a8-47a4-bdef-83b51c933b39', 'SQL and Relational Databases', 'Sql-and-relational-databases', 'Master database management and SQL programming for data analysis and application development. Learn database design, complex queries, performance optimization, and data modeling to efficiently store, retrieve, and analyze organizational data.', 0) ON CONFLICT DO NOTHING;
INSERT INTO courses (id, path_id, title, slug, description, order_index) VALUES ('e3c50a58-1c79-46df-a8c0-6fde786a7617', '251e65a0-3e44-4a0e-b18a-78fe5d7a1366', 'Google Analytics', 'Google-analytics', 'Master Google Analytics 4 to track, analyze, and optimize website performance. Learn audience segmentation, conversion tracking, attribution modeling, and reporting to make data-driven decisions that improve digital marketing ROI and user experience.', 0) ON CONFLICT DO NOTHING;
INSERT INTO courses (id, path_id, title, slug, description, order_index) VALUES ('56e62a83-fecc-45c3-a56a-feb3c84ccdab', '251e65a0-3e44-4a0e-b18a-78fe5d7a1366', 'Learn Meta Ads', 'Learn-Meta-Ads', 'Master Facebook and Instagram advertising to drive business growth. Learn campaign structure, audience targeting, creative optimization, budget management, and performance analysis to create profitable ad campaigns across Meta''s advertising platforms.', 0) ON CONFLICT DO NOTHING;
