INSERT INTO courses (id, path_id, title, slug, description, order_index) VALUES ('814266db-1523-4b6e-a3ea-7fa97a34c87c', '15d8db2d-ea90-4e85-8d2b-b42a15bf5c0c', 'Prompt Engineering Mastery', 'Prompt-Engineering-Mastery', 'Master the art of AI communication through systematic prompt engineering. Learn 20+ proven frameworks including APE, RACE, ROSES, and TRACE to unlock AI''s full potential. Transform from beginner to expert with hands-on projects and real-world applications.', 0) ON CONFLICT DO NOTHING;
